const express = require('express');
const jwt = require('jsonwebtoken');
const axios = require('axios');

const app = express();
app.use(express.json());

const clientId = 'your_client_id';
const clientSecret = 'your_client_secret';
const issuerUrl = 'https://your-issuer-url.com';

// OIDC authorization endpoint
app.get('/login', (req, res) => {
  const authUrl = `${issuerUrl}/authorize?response_type=code&client_id=${clientId}&redirect_uri=http://localhost:3000/callback`;
  res.redirect(authUrl);
});

// Callback endpoint to receive authorization code
app.get('/callback', async (req, res) => {
  const code = req.query.code;
  if (!code) {
    return res.status(401).send('Unauthorized');
  }

  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(`${issuerUrl}/token`, {
      grant_type: 'authorization_code',
      code,
      redirect_uri: 'http://localhost:3000/callback',
      client_id: clientId,
      client_secret: clientSecret,
    });

    const idToken = tokenResponse.data.id_token;
    if (!idToken) {
      return res.status(401).send('Unauthorized');
    }

    // Decode ID token
    const decodedClaims = jwt.decode(idToken, { complete: true });
    if (!decodedClaims.payload || !decodedClaims.header) {
      return res.status(401).send('Unauthorized');
    }

    // Create user session based on decoded claims
    req.session.user = decodedClaims.payload;
    res.redirect('/protected');
  } catch (error) {
    console.error(error);
    res.status(500).send('Internal Server Error');
  }
});

// Protected route
app.get('/protected', (req, res) => {
  if (!req.session.user) {
    return res.status(401).send('Unauthorized');
  }

  const user = req.session.user;
  res.send(`Hello, ${user.name}! Your email is: ${user.email}`);
});

const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});